  1→/**
  2→ * Intent Node Acceptance Test Kit
  3→ *
  4→ * Extends the orchestrator-test-kit with intent-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST /api/intents/:id/evaluate  (SurrealQL EVENT target)
  9→ *   POST /api/intents/:id/veto      (human veto)
 10→ *   MCP tools: create_intent, submit_intent, get_intent_status
 11→ */
 12→import { RecordId, type Surreal } from "surrealdb";
 13→
 14→// Re-export everything from orchestrator-test-kit
 15→export {
 16→  setupOrchestratorSuite,
 17→  createTestUser,
 18→  createTestWorkspace,
 19→  createReadyTask,
 20→  createTestProject,
 21→  getTestUserBearerToken,
 22→  fetchJson,
 23→  fetchRaw,
 24→  type OrchestratorTestRuntime,
 25→  type TestUser,
 26→  type TestUserWithToken,
 27→  type TestWorkspace,
 28→  type TestTask,
 29→  type TestProject,
 30→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 31→
 32→import {
 33→  fetchJson,
 34→  fetchRaw,
 35→  type TestUser,
 36→  type TestUserWithToken,
 37→} from "../coding-agent-orchestrator/orchestrator-test-kit";
 38→
 39→// ---------------------------------------------------------------------------
 40→// Intent-Specific Types
 41→// ---------------------------------------------------------------------------
 42→
 43→export type IntentStatus =
 44→  | "draft"
 45→  | "pending_auth"
 46→  | "pending_veto"
 47→  | "authorized"
 48→  | "executing"
 49→  | "completed"
 50→  | "vetoed"
 51→  | "failed";
 52→
 53→export type ActionSpec = {
 54→  provider: string;
 55→  action: string;
 56→  params?: Record<string, unknown>;
 57→};
 58→
 59→export type BudgetLimit = {
 60→  amount: number;
 61→  currency: string;
 62→};
 63→
 64→export type EvaluationResult = {
 65→  decision: "APPROVE" | "REJECT";
 66→  risk_score: number;
 67→  reason: string;
 68→  evaluated_at: string;
 69→  policy_only: boolean;
 70→};
 71→
 72→export type IntentRecord = {
 73→  id: RecordId<"intent">;
 74→  goal: string;
 75→  reasoning: string;
 76→  status: IntentStatus;
 77→  priority: number;
 78→  action_spec: ActionSpec;
 79→  budget_limit?: BudgetLimit;
 80→  evaluation?: EvaluationResult;
 81→  veto_expires_at?: string;
 82→  veto_reason?: string;
 83→  error_reason?: string;
 84→  trace_id: string;
 85→  created_at: string;
 86→  updated_at?: string;
 87→};
 88→
 89→export type CreateIntentOptions = {
 90→  goal: string;
 91→  reasoning: string;
 92→  priority?: number;
 93→  action_spec: ActionSpec;
 94→  budget_limit?: BudgetLimit;
 95→  taskId?: string;
 96→};
 97→
 98→// ---------------------------------------------------------------------------
 99→// Domain Helpers -- Business Language Layer
100→// ---------------------------------------------------------------------------
101→
102→/**
103→ * Creates a draft intent directly in the database.
104→ * Used as a Given-step precondition for scenarios that start
105→ * with an intent already in draft status.
106→ */
107→export async function createDraftIntent(
108→  surreal: Surreal,
109→  workspaceId: string,
110→  requesterId: string,
111→  opts: CreateIntentOptions,
112→): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
