302→ */
303→export async function getIntentStatusViaMcp(
304→  baseUrl: string,
305→  user: TestUserWithToken,
306→  workspaceId: string,
307→  intentId: string,
308→): Promise<{ intentId: string; status: IntentStatus }> {
