314→      body: JSON.stringify({ intent_id: intentId }),
315→    },
316→  );
317→}
318→
319→/**
320→ * Polls until an intent reaches the target status or times out.
321→ * Used to wait for async evaluation pipeline (SurrealQL EVENT -> evaluate -> status update).
322→ */
323→export async function waitForIntentStatus(
324→  surreal: Surreal,
325→  intentId: string,
326→  targetStatus: IntentStatus | IntentStatus[],
327→  timeoutMs = 30_000,
328→): Promise<IntentStatus> {
329→  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
330→  const start = Date.now();
331→
332→  while (Date.now() - start < timeoutMs) {
333→    const current = await getIntentStatus(surreal, intentId);
334→    if (targets.includes(current)) {
335→      return current;
336→    }
337→    await Bun.sleep(250);
338→  }
339→
340→  const finalStatus = await getIntentStatus(surreal, intentId);
341→  throw new Error(
342→    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
343→    `Current status: ${finalStatus}`,
344→  );
345→}
346→
347→/**
348→ * Simulates the evaluation endpoint completing (for tests where the
349→ * SurrealQL EVENT may not fire in the test environment).
350→ * Directly updates the intent with an evaluation result and new status.
351→ */
352→export async function simulateEvaluation(
353→  surreal: Surreal,
354→  intentId: string,
355→  evaluation: {
356→    decision: "APPROVE" | "REJECT";
357→    risk_score: number;
358→    reason: string;
359→    policy_only?: boolean;
360→  },
361→  resultStatus: IntentStatus,
362→): Promise<void> {
363→  const intentRecord = new RecordId("intent", intentId);
364→  const evalContent = {
365→    decision: evaluation.decision,
366→    risk_score: evaluation.risk_score,
367→    reason: evaluation.reason,
368→    evaluated_at: new Date(),
369→    policy_only: evaluation.policy_only ?? false,
370→  };
371→
372→  const updates: Record<string, unknown> = {
373→    status: resultStatus,
374→    evaluation: evalContent,
375→    updated_at: new Date(),
376→  };
377→
378→  // If entering veto window, set expiry
379→  if (resultStatus === "pending_veto") {
380→    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 min default
381→    updates.veto_expires_at = expiresAt;
382→  }
383→
384→  await surreal.query(`UPDATE $intent MERGE $updates;`, {
385→    intent: intentRecord,
386→    updates,
387→  });
388→}
389→
390→/**
391→ * Queries the identity record for a user to get the identity ID.
392→ * Needed because intent.requester links to identity, not user.
393→ */
394→export async function getIdentityId(
395→  surreal: Surreal,
396→): Promise<string> {
397→  const rows = (await surreal.query(
398→    `SELECT id FROM identity LIMIT 1;`,
399→  )) as Array<Array<{ id: RecordId<"identity"> }>>;
400→  const result = rows[0]?.[0];
401→  if (!result) {
402→    throw new Error("No identity found -- create a test user first");
403→  }
404→  return result.id.id as string;
405→}
406→
407→/**
408→ * Creates a test identity directly in the database.
409→ * Used when we need an identity record without going through auth.
410→ */
411→export async function createTestIdentity(
412→  surreal: Surreal,
413→  name: string,
414→  type: "human" | "agent" = "agent",
415→  workspaceId?: string,
416→): Promise<string> {
417→  const identityId = `id-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
418→  const identityRecord = new RecordId("identity", identityId);
419→
420→  const content: Record<string, unknown> = {
421→    name,
422→    type,
423→    created_at: new Date(),
424→  };
425→
426→  if (workspaceId) {
427→    content.workspace = new RecordId("workspace", workspaceId);
428→  }
429→
430→  await surreal.query(`CREATE $identity CONTENT $content;`, {
431→    identity: identityRecord,
432→    content,
433→  });
434→  return identityId;
435→}
436→
437→/**
438→ * Wires the SurrealQL EVENT that fires when an intent transitions to
439→ * pending_auth. The EVENT calls http::post to the real test server's
440→ * evaluate endpoint, enabling true E2E testing of the async evaluation flow.
441→ *
442→ * Call this in beforeAll after the test server has booted.
443→ */
444→export async function wireIntentEvaluationEvent(
445→  surreal: Surreal,
446→  port: number,
447→): Promise<void> {
448→  const baseUrl = `http://127.0.0.1:${port}`;
449→  await surreal.query(`
450→    DEFINE EVENT OVERWRITE intent_pending_auth ON intent
451→      WHEN $before.status != "pending_auth" AND $after.status = "pending_auth"
452→      THEN {
453→        http::post("${baseUrl}/api/intents/" + <string> meta::id($after.id) + "/evaluate", $after)
454→      };
455→  `);
456→}
457→

